            airport_info.append(f"has a location identifier of {obj}")
        elif predicate == "iataLocationIdentifier":
            airport_info.append(f"has an IATA code of {obj}")
        elif predicate == "nativeName":
            airport_info.append(f"is also known as {obj}")
        elif predicate == "operatingOrganisation":
            airport_info.append(f"is operated by {obj}")
        elif predicate == "owner":
