                        if sub_pred == "language":
                            sentence_parts.append(f"where {sub_obj} is spoken")
                        elif sub_pred == "leader":
                            sentence_parts.append(f"led by {sub_obj}")
                        elif sub_pred == "officialLanguage":
                            sentence_parts.append(f"with {sub_obj} as its official language")
                        elif sub_pred == "capital":
                            sentence_parts.append(f"whose capital is {sub_obj}")
